#include <stdio.h>
#include <string.h>

int main() {
    int T; if (scanf("%d", &T)!=1) return 0;
    while (T--) {
        char X[100005], Y[100005];
        scanf("%s", X);
        scanf("%s", Y);
        int n = strlen(X);
        char Z[100005];
        for (int i = 0; i < n; ++i) {
            if (X[i] == Y[i]) {
                Z[i] = (X[i] == 'B') ? 'W' : 'B';
            } else {
                Z[i] = 'B';
            }
        }
        Z[n] = '\0';
        printf("%s\n", Z);
    }
    return 0;
}

