import sys

def solve():
    data = sys.stdin.read().strip().split()
    if not data:
        return
    t = int(data[0])
    idx = 1
    out_lines = []
    for _ in range(t):
        X = data[idx]; Y = data[idx+1]; idx += 2
        n = len(X)
        Z_chars = []
        for i in range(n):
            if X[i] == Y[i]:
                Z_chars.append('W' if X[i] == 'B' else 'B')
            else:
                Z_chars.append('B')
        out_lines.append(''.join(Z_chars))
    sys.stdout.write('\n'.join(out_lines))

if __name__ == "__main__":
    solve()

